mapper.select:
SELECT r.id, r.role_name AS roleName, r.role_code AS roleCode, r.description, r.status, r.create_time AS createTime, r.update_time AS updateTime, GROUP_CONCAT(p.permission_code ORDER BY p.id SEPARATOR ',') AS permissionCodes, GROUP_CONCAT(p.permission_name ORDER BY p.id SEPARATOR ',') AS permissionNames FROM `sys_role` r LEFT JOIN `sys_role_permission` rp ON r.id = rp.role_id LEFT JOIN `sys_permission` p ON rp.permission_id = p.id
AND r.role_name LIKE CONCAT('%', #{roleName}, '%') AND r.role_code LIKE CONCAT('%', #{roleCode}, '%') AND r.status = #{status}
GROUP BY r.id, r.role_name, r.role_code, r.description, r.status, r.create_time, r.update_time ORDER BY r.id DESC LIMIT #{pageSize} OFFSET #{offset}

mapper.update:
UPDATE `sys_role`
role_name = #{roleName}, role_code = #{roleCode}, description = #{description}, status = #{status}, update_time = CURRENT_TIMESTAMP,
WHERE id = #{id}
